class Student:
    def __init__(self, name, marks):
        self.name = name
        self.marks = marks

    def check_pass(self):
        if self.marks > 40:
            print("Pass")
        else:
            print("Fail")

name_input = input()
marks_input = int(input())

s1 = Student(name_input, marks_input)
s1.check_pass()
